fn binary_search(arr: &[i32], l: usize, r: usize, target: i32) -> i32 {
    let mut left = l;
    let mut right = r;

    // Safety check for empty range or right < left if not handled by caller
    if left > right { return -1; }

    while left <= right {
        let mid = left + (right - left) / 2;
        if arr[mid] == target {
            return mid as i32;
        }
        if arr[mid] < target {
            left = mid + 1;
        } else {
            if mid == 0 { break; } // avoid underflow
            right = mid - 1;
        }
    }
    -1
}

